    blacklist = {"__future__", "typing", "builtins", "os", "sys"}

    def is_valid(lib):
        if lib in blacklist:
            return False
        if lib in stdlib_modules:
            return False
        return not lib.startswith("meta") and not lib.startswith("tools") and not lib.startswith("project")

    filtered = sorted(set(lib for lib in all_imports if is_valid(lib)))

    import json
    with open("requirements.json", "w") as f:
        json.dump({"required_libraries": filtered}, f, indent=2)

    print("✅ requirements.json généré avec les imports suivants :")
    print(json.dumps({"required_libraries": filtered}, indent=2))
    return {"required_libraries": filtered}


